//  ГўвҖўЕЎГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВқ ГўвҖўЕЎГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВқ ГўвҖўЕЎГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВқ  ГўвҖўЕЎГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВқ  ГўвҖўЕЎГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВқ       ГўвҖўЕЎГўвҖўВҗГўвҖўВқ
//
//  HTML DO CABEГғвҖЎALHO NOC
//
//  Aguarda o elemento #bpc-header-root no DOM (injectado pelo painel
//  Grafana "Text") e preenche-o com o cabeГғВ§alho.
//
//  ContГғВ©m:
//    ГўвӮ¬Вў FunГғВ§ГғВЈo renderHeader(el) ГўвҖ вҖҷ gera o HTML do cabeГғВ§alho
//    ГўвӮ¬Вў FunГғВ§ГғВЈo renderClock()    ГўвҖ вҖҷ actualiza hora + data a cada segundo
//    ГўвӮ¬Вў Polling para #bpc-header-root (timeout 10s)
//
//  Todo o texto e aparГғВӘncia vГғВӘm de CFG_HEADER, CFG_SIZES, CFG_THEME (BLOCO 1).
//
// ГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗГўвҖўВҗ

(function initHeader() {

  // ГўвҖқвӮ¬ГўвҖқвӮ¬ renderClock ГўвӮ¬вҖқ actualiza #bpc-clock-time e #bpc-clock-date ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬

  function renderClock() {
    const now = new Date();
    const pad = n => String(n).padStart(2, '0');
    const tEl = document.getElementById('bpc-clock-time');
    const dEl = document.getElementById('bpc-clock-date');
    if (!tEl || !dEl) return;
    tEl.textContent =
      pad(now.getHours()) + ':' + pad(now.getMinutes()) + ':' + pad(now.getSeconds());
    dEl.textContent =
      CFG_CLOCK.days[now.getDay()] + ', ' +
      now.getDate() + ' de ' +
      CFG_CLOCK.months[now.getMonth()] + ' de ' +
      now.getFullYear();
  }


  // ГўвҖқвӮ¬ГўвҖқвӮ¬ renderHeader ГўвӮ¬вҖқ gera o HTML e inicia o relГғВіgio ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
  //
  //  Estrutura:
  //    .bpc-noc-hdr
  //    ГўвҖқЕ“ГўвҖқвӮ¬ГўвҖқвӮ¬ [logo ou fallback textual]
  //    ГўвҖқЕ“ГўвҖқвӮ¬ГўвҖқвӮ¬ .bpc-noc-center  (tГғВӯtulo + subtГғВӯtulo)
  //    ГўвҖқвҖқГўвҖқвӮ¬ГўвҖқвӮ¬ .bpc-noc-right   (relГғВіgio + data)

  function renderHeader(el) {
    const C = CFG_HEADER;
    const Z = CFG_SIZES;

    // LogГғВіtipo: tenta carregar a imagem; se falhar, mostra fallback textual
    const logoHTML = C.logoUrl
      ? `<img src="${C.logoUrl}"
              height="${Z.logo.height}"
              class="bpc-noc-logo"
              onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">
         <div class="bpc-noc-logo-fallback" style="display:none">${C.title}</div>`
      : `<div class="bpc-noc-logo-fallback">${C.title}</div>`;

    const backHTML = C.backLink
      ? `<a href="${C.backLink.url}" style="display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:4px;background:rgba(255,255,255,0.07);color:rgba(255,255,255,0.55);font-size:.78rem;font-weight:600;letter-spacing:.04em;text-decoration:none;border:1px solid rgba(255,255,255,0.10);transition:background .15s" onmouseover="this.style.background='rgba(255,255,255,0.13)'" onmouseout="this.style.background='rgba(255,255,255,0.07)'">${C.backLink.label}</a>`
      : '';

    el.innerHTML = `
      <div class="bpc-noc-hdr">

        <!-- Logotipo + back-link -->
        <div style="display:flex;flex-direction:column;align-items:flex-start;gap:6px;flex-shrink:0">
          <div style="display:flex;align-items:center;gap:10px">
            ${logoHTML}
          </div>
          ${backHTML}
        </div>

        <!-- Titulo + Subtitulo -->
        <div class="bpc-noc-center">
          <div class="bpc-noc-title">
            ${C.title} &nbsp;|&nbsp; <em>${C.nocLabel}</em>
          </div>
          ${C.subtitle ? `<div class="bpc-noc-sub">${C.subtitle}</div>` : ''}
        </div>

        <!-- Relogio -->
        <div class="bpc-noc-right">
          <span class="bpc-noc-time" id="bpc-clock-time">--:--:--</span>
          <div  class="bpc-noc-date" id="bpc-clock-date">...</div>
        </div>

      </div>`;

    // Inicia o relГғВіgio (limpa timer anterior se o header for re-renderizado)
    if (window._bpc_clock_interval) clearInterval(window._bpc_clock_interval);
    renderClock();
    window._bpc_clock_interval = setInterval(renderClock, 1000);

    if (window.BPC?.log) BPC.log('Header renderizado (' + CFG_META.version + ')');
  }


  // ГўвҖқвӮ¬ГўвҖқвӮ¬ Aguardar #bpc-header-root no DOM ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
  //
  //  O Grafana injecta os painГғВ©is de forma assГғВӯncrona; o elemento pode
  //  ainda nГғВЈo existir quando este script executa.
  //  Polling a cada 50ms com timeout de 10s.

  const t0 = Date.now();
  const poll = setInterval(() => {
    const el = document.getElementById('bpc-header-root');
    if (el) {
      clearInterval(poll);
      renderHeader(el);
      return;
    }
    if (Date.now() - t0 > 10000) {
      clearInterval(poll);
      console.warn('[BPC] Header: #bpc-header-root nГғВЈo encontrado apГғВіs 10s');
    }
  }, 50);

})(); // fim BLOCO 3


