            <div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-md bpc-crit">${d.down}</span><span class="bpc-label">Down</span></div>
            <div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-md bpc-warn">${d.warn}</span><span class="bpc-label">Degradado</span></div>
            <div class="bpc-flex-col bpc-gap-4" style="margin-left:auto;text-align:right">
              <span class="bpc-value-md ${aC}">${avail}%</span>
              <span class="bpc-label">Disponib.</span>
            </div>
          </div>
          <div class="bpc-flex bpc-gap-12">
            <div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-sm bpc-info">${rttLabel}</span><span class="bpc-label">RTT mГғВ©dio</span></div>
            <div class="bpc-flex-col bpc-gap-4"><span class="bpc-value-sm ${lossClass}">${lossLabel}</span><span class="bpc-label">Loss mГғВ©dio</span></div>
          </div>
          ${bar}
          <div class="bpc-flex" style="justify-content:space-between;margin-top:auto;padding-top:4px">
            <span style="font-size:.68rem;color:var(--bpc-cyan)">Ver detalhe ГўвҖ вҖҷ</span>
            <span class="bpc-timestamp">Grupo ${cfg.groupid || 'ГўвӮ¬вҖқ'}</span>
          </div>
        </div>
      </a>`;
    },


    // ГўвҖқвӮ¬ГўвҖқвӮ¬ Builder ГўвӮ¬вҖқ buildError ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
    //
    //  Card de erro inline ГўвӮ¬вҖқ exibido quando uma chamada RPC falha.
